def _symmetries(template):
    grid = [list(row) for row in template]
    result = set()
    current = grid
    for _ in range(4):
        result.add(tuple(''.join(row) for row in current))
        result.add(tuple(''.join(row[::-1]) for row in current))
        current = [list(row) for row in zip(*current[::-1])]
    return result


TEMPLATES = set()
for _template in _BASE_TEMPLATES:
    TEMPLATES.update(_symmetries(_template))


def _guess_marker(grid, source):
    counts = Counter(value for row in grid for value in row)
    candidates = [(value, count) for value, count in counts.items() if value != source]
    if not candidates:
        return None
    value, count = min(candidates, key=lambda item: item[1])
    if count < (len(grid) * len(grid[0])) // 5:
        return value
    return None


def _patch(grid, row, col, mapping, radius=2):
    height, width = len(grid), len(grid[0])
    return tuple(
        ''.join(
            mapping.get(grid[r][c], 'O') if 0 <= r < height and 0 <= c < width else '#'
            for c in range(col - radius, col + radius + 1)
        )
        for r in range(row - radius, row + radius + 1)
    )


def _mapping(grid, source):
    mapping = {source: 'S'}
    marker = _guess_marker(grid, source)
    if marker is not None:
        mapping[marker] = 'M'
    return mapping


def _best_template_matches(grid):
    colors = sorted({value for row in grid for value in row if value != 7})
    best_source = None
    best_matches = []
    for source in colors:
        mapping = _mapping(grid, source)
        matches = []
        for row in range(len(grid)):
            for col in range(len(grid[0])):
                if grid[row][col] == source and _patch(grid, row, col, mapping) in TEMPLATES:
                    matches.append((row, col))
        if len(matches) > len(best_matches):
            best_source = source
            best_matches = matches
    return best_source, best_matches


def _cross_fallback(grid):
    counts = Counter(value for row in grid for value in row)
    marker_candidates = [(value, count) for value, count in counts.items() if value != 7 and count > 1]
    if not marker_candidates:
        return None, []
    marker, count = min(marker_candidates, key=lambda item: item[1])
    if count >= (len(grid) * len(grid[0])) // 5:
        return None, []

    markers = {(r, c) for r, row in enumerate(grid) for c, value in enumerate(row) if value == marker}
    used = set()
    crosses = []
    height, width = len(grid), len(grid[0])
    candidates = []
    for row in range(height):
        for col in range(width):
            cross = {(row, col + dc) for dc in range(-2, 3) if 0 <= col + dc < width}
            cross |= {(row + dr, col) for dr in range(-2, 3) if 0 <= row + dr < height}
            hits = sorted(markers & cross)
            if len(hits) >= 2:
                score = (len(hits), sum((p in markers) for p in cross))
                candidates.append((score, (row, col), cross, hits))
    candidates.sort(reverse=True)
    for _, center, cross, hits in candidates:
        fresh = [cell for cell in hits if cell not in used]
        if len(fresh) >= 2:
            used.update(hits)
            crosses.append((center, cross, hits))
    if not crosses:
        return None, []
    changes = []
    for _, cross, _ in crosses:
        for row, col in cross:
            if grid[row][col] != marker and grid[row][col] != 7:
                changes.append((row, col))
    return marker, sorted(set(changes))


def _hamming(a, b):
    return sum(x != y for x, y in zip(a, b))


def _nearest_neighbor_fallback(grid):
    colors = sorted({value for row in grid for value in row if value != 7})
    best_source = None
    best_matches = []
    changed = [''.join(t) for t in _CHANGED_TEMPLATES]
    unchanged = [''.join(t) for t in _UNCHANGED_TEMPLATES]
    for source in colors:
        mapping = _mapping(grid, source)
        matches = []
        for row in range(len(grid)):
            for col in range(len(grid[0])):
                if grid[row][col] != source:
                    continue
                patch = ''.join(_patch(grid, row, col, mapping))
                if min(_hamming(patch, other) for other in changed) < min(_hamming(patch, other) for other in unchanged):
                    matches.append((row, col))
        if len(matches) > len(best_matches):
            best_source = source
            best_matches = matches
    return best_source, best_matches


def transform(grid):
    output = [row[:] for row in grid]

    source, matches = _best_template_matches(grid)
    if matches:
        for row, col in matches:
            output[row][col] = 7
        return output

    marker, matches = _cross_fallback(grid)
    if matches:
        for row, col in matches:
            output[row][col] = 7
        return output

    source, matches = _nearest_neighbor_fallback(grid)
    for row, col in matches:
        output[row][col] = 7
    return output
